// useCreatureTracker.js — reactive for mutable state
const creature = reactive({ lat: 0, lng: 0, icon: '🐯', name: 'Auntie Tigress' })

watch(homePosition, (home) => {
 radius = 0.008 + Math.random() * 0.004
 updatePosition(home)
}, { immediate: true })

